// Step 1: Contract requests data from oracle
function requestPriceData(string coinPair) public {
 // Generate unique request ID
 requestId = keccak256(coinPair, block.timestamp);

 // Call oracle contract to fetch data
 oracleContract.requestData(
 requestId,
 coinPair,
 this.fulfillPriceData.selector // callback function
 );
}

// Step 2: Oracle calls back with data
function fulfillPriceData(
 bytes32 requestId,
 uint256 price
) public {
 // Verify request ID matches
 require(requestId == pendingRequests[requestId]);

 // Store the price data
 priceData[requestId] = price;

 // Emit event for transparency
 emit PriceUpdated(requestId, price);
}

// Oracle nodes report their data
struct OracleReport {
 address nodeAddress;
 uint256 price;
 uint256 timestamp;
 bytes signature;
}

function processOracleReports(
 OracleReport[] reports,
 uint256 minimumResponses
) public returns (uint256) {
 // Require minimum number of responses
 require(reports.length >= minimumResponses, "Insufficient responses");

 // Extract all prices into array
 uint256[] memory prices = new uint256[](reports.length);
 for (uint i = 0; i < reports.length; i++) {
 // Verify signature for authenticity
 require(verifySignature(reports[i]), "Invalid signature");
 prices[i] = reports[i].price;
 }

 // Sort prices to find median
 sort(prices);

 // Return median (most common consensus approach)
 uint256 medianPrice = prices[prices.length / 2];

 // Update final price
 finalPrice = medianPrice;

 emit ConsensusReached(medianPrice, reports.length);
 return medianPrice;
}

// Insurance policy contract with oracle integration
struct Policy {
 address policyHolder;
 uint256 premium;
 uint256 payoutAmount;
 uint256 temperatureThreshold;
 uint256 duration;
 bool isActive;
}

// Oracle calls this when weather conditions are breached
function fulfillWeatherData(
 bytes32 requestId,
 uint256 temperature,
 uint256 humidity,
 uint256 timestamp
) public onlyOracle {
 Policy storage policy = policies[requestId];

 // Verify data freshness (within last hour)
 require(block.timestamp - timestamp < 3600, "Stale data");

 // Check if conditions trigger payout
 if (temperature > policy.temperatureThreshold) {
 // Trigger payout to policy holder
 policy.isActive = false;

 // Transfer payout (in real scenario, use safe math)
 payable(policy.policyHolder).transfer(policy.payoutAmount);

 emit ClaimPaid(requestId, policy.payoutAmount, temperature);
 }
}

// Function to purchase policy
function purchasePolicy(
 uint256 temperatureThreshold,
 uint256 duration
) public payable returns (bytes32) {
 // Require premium payment
 require(msg.value >= PREMIUM_AMOUNT, "Insufficient premium");

 bytes32 policyId = keccak256(
 abi.encodePacked(msg.sender, block.timestamp)
 );

 policies[policyId] = Policy({
 policyHolder: msg.sender,
 premium: msg.value,
 payoutAmount: msg.value * 10, // 10x payout
 temperatureThreshold: temperatureThreshold,
 duration: duration,
 isActive: true
 });

 // Request weather data from oracle
 oracleContract.requestWeatherData(policyId);

 return policyId;
}
